function bool HasAccountAccess(int accountId)
{
  bool systemFreeze =
    this.Accounts.Any(a => a.IsFrozen);
  Predicate[Account] accountMatch;
  accountMatch =
    accountMatch.Create(
      a => a.AccountId == accountId && !systemFreeze);
  if (this.Accounts.Any(
        a => a.AccountId == accountId && a.IsOpen))
  { return true; }
  bool managerAccess =
    this.Managers.Any(
      m => m.AccountRights.Any(accountMatch));
  return managerAccess;
}

