function bool IsMilestoneReadyForClosure(int milestoneId)
{
    Domain.Milestone ms = this.Milestones.First(m => m.Id == milestoneId);
    Collection[Domain.Task] pendingTasks = ms.Tasks.Where(t => t.Status != "Completed");
    bool hasCriticalBlockers = pendingTasks.Any(t => t.Priority == "Blocker");
    return pendingTasks.Length == 0 && !hasCriticalBlockers && ms.ApprovalDate != null;
}

