function void ParseInner(Domain.Statute s, int year) {
    foreach sub in s.SubSections {
        if (sub.SubSections.Length > 0) {
            this.ParseInner(sub, year);
        }
        else if (year > 2000) {
            this.Flag(sub, year);
        }
    }
}

