function void AuditCategories(Domain.Category root, int targetDepth) {
    int level = 1;
    foreach cat in root.SubCategories {
        if (level >= targetDepth) {
            this.AddtoAuditList(cat, level);
        }
        if (cat.SubCategories.Length > 0) {
            this.AuditInner(cat, level, targetDepth);
        }
    }
}
function void AuditInner(Domain.Category c, int level, int target) {
    level = level + 1;
    foreach sub in c.SubCategories {
        if (sub.SubCategories.Length > 0) {
            this.AuditInner(sub, level, target);
        }
        else if (level >= target) {
            this.AddtoAuditList(sub, level);
        }
    }
}

