function void Audit(Domain.Category node, int level, int target) {
    bool isDeepEnough = level >= target;
    if (isDeepEnough) this.AddtoAuditList(node, level);
    foreach sub in node.SubCategories {
        this.Audit(sub, level + 1, target);
    }
}

