function bool IsPrime(int n) {
    if n < 2 {
        return false;
    }
    int i = 2;
    double limit = CommonLib.Math.Sqrt(n);
    while i <= limit {
        if n % i == 0 {
            return false;
        }
        i = i + 1;
    }
    return true;
}
