function decimal CalculatePay(int hours, decimal rate)
{ decimal NormalHours = 40;
  decimal OvertimePayFactor = 1.5;
  int regularHours = CommonLib.Math.Min(hours, NormalHours);
  int overtimeHours = CommonLib.Math.Max(0, hours - NormalHours);
  decimal regularPay = regularHours * rate;
  decimal overtimePay = overtimeHours * rate * OvertimePayFactor;
  decimal totalPay = regularPay + overtimePay;
  return totalPay;
}
