static function EducationModel.CourseRegistry initCourseRegistry(EducationModel.Student student, EducationModel.Semester semester)
{
    CourseType courseKind = CourseType.GetTypeOf(course);
    EducationModel.MathCourse prototypeMath = EducationModel.MathCourse.Create();
    EducationModel.ScienceCourse prototypeScience = EducationModel.ScienceCourse.Create();
    EducationModel.HistoryCourse prototypeHistory = EducationModel.HistoryCourse.Create();
    CourseType mathKind = CourseType.GetTypeOf(prototypeMath);
    CourseType scienceKind = CourseType.GetTypeOf(prototypeScience);
    CourseType historyKind = CourseType.GetTypeOf(prototypeHistory);
    EducationModel.CourseRegistry registry = EducationModel.CourseRegistry.Create();
    registry.studentRef = student;
    registry.activeSemester = semester;
    if(courseKind.Name == mathKind.Name) {
        registry.mathCourse = course as EducationModel.MathCourse; }
    elseif(courseKind.Name == scienceKind.Name) {
        registry.scienceCourse = course as EducationModel.ScienceCourse; }
    elseif(courseKind.Name == historyKind.Name) {
        registry.historyCourse = course as EducationModel.HistoryCourse; }
    return registry;
}

