function void Index(Domain.Site root, int depthLimit) {
    foreach data in root.Readings {
        if (depthLimit > 0) {
            this.Store(data, depthLimit);
        }
    }
    if (root.Stations.Length > 0) {
        this.IndexInner(root, depthLimit);
    }
}
function void IndexInner(Domain.Site s, int limit) {
    foreach st in s.Stations {
        if (st.Stations.Length > 0) {
            this.IndexInner(st, limit);
        }
        else if (limit > 0) {
            this.Store(st, limit);
        }
    }
}

