static function HomeModel.DeviceGroup initDeviceGroup(HomeModel.Room room)
{
    DeviceKind detectedKind = DeviceKind.GetTypeOf(device);
    HomeModel.LightDevice sampleLight = HomeModel.LightDevice.Create();
    HomeModel.CameraDevice sampleCamera = HomeModel.CameraDevice.Create();
    HomeModel.SensorDevice sampleSensor = HomeModel.SensorDevice.Create();
    DeviceKind lightKind = DeviceKind.GetTypeOf(sampleLight);
    DeviceKind cameraKind = DeviceKind.GetTypeOf(sampleCamera);
    DeviceKind sensorKind = DeviceKind.GetTypeOf(sampleSensor);
    HomeModel.DeviceGroup group = HomeModel.DeviceGroup.Create();
    group.roomRef = room;
    group.isInitialized = true;
    group.unknownDevice = null;
    if(detectedKind.Name == sensorKind.Name)
    {
        group.sensorDevice = device as HomeModel.SensorDevice;
        group.lastPriority = 1;
    }
    elseif(detectedKind.Name == cameraKind.Name)
    {
        group.cameraDevice = device as HomeModel.CameraDevice;
        group.lastPriority = 2;
    }
    elseif(detectedKind.Name == lightKind.Name)
    {
        group.lightDevice = device as HomeModel.LightDevice;
        group.lastPriority = 3;
    }
    else
    {
        group.unknownDevice = device;
        group.lastPriority = 99;
    }
    return group;
}

