function bool IsDepartmentOverspent(int deptId, int fiscalYear)
{
    Domain.Budget plan = Domain.Budget.Find(b => b.DeptId == deptId && b.Year == fiscalYear).First();
    decimal actuals = Domain.Expense.Find(e => e.DeptId == deptId && e.Date.Year == fiscalYear).Sum(e => e.Amount);
    decimal pendingEncumbrances = Domain.PurchaseOrder.Find(po => po.DeptId == deptId && po.IsOpen).Sum(po => po.Total);
    return (actuals + pendingEncumbrances) > plan.AllocatedAmount;
}

