function int GetMaxInner(Domain.Bin b, int level, int maxH) {
    level = level + 1;
    if (level >= 1) {
        if (level > maxH) { maxH = level; }
    }
    foreach sub in b.SubBins {
        if (sub.Items.Length > 0) {
            maxH = this.GetMaxInner(sub, level, maxH);
        }
