function void MapSpecies(Domain.Tree root, string filter) {
    int level = 1;
    foreach branch in root.Branches {
        if (filter != "") {
            this.Register(branch, level, filter);
        }
        if (branch.Branches.Length > 0) {
            this.MapInner(branch, level, filter);
        }
    }
}
function void MapInner(Domain.Tree t, int level, string f) {
    level = level + 1;
    foreach b in t.Branches {
        if (b.Branches.Length > 0) {
            this.MapInner(b, level, f);
        }
        else if (f != "") {
            this.Register(b, level, f);
        }
    }
}

