static function FinanceModel.TransactionWrapper initTransactionWrapper(FinanceModel.Account account)
{
    SegmentType transactionKind = SegmentType.GetTypeOf(transaction);
    FinanceModel.DepositTransaction prototypeDeposit = FinanceModel.DepositTransaction.Create();
    FinanceModel.WithdrawTransaction prototypeWithdraw = FinanceModel.WithdrawTransaction.Create();
    SegmentType depositKind = SegmentType.GetTypeOf(prototypeDeposit);
    SegmentType withdrawKind = SegmentType.GetTypeOf(prototypeWithdraw);
    FinanceModel.TransactionWrapper wrapper = FinanceModel.TransactionWrapper.Create();
    wrapper.accountRef = account;
    if(transactionKind.Name == depositKind.Name) {
        wrapper.depositTransaction = transaction as FinanceModel.DepositTransaction; }
    elseif(transactionKind.Name == withdrawKind.Name) {
        wrapper.withdrawTransaction = transaction as FinanceModel.WithdrawTransaction; }
    return wrapper;
}

