static function InsuranceModel.PolicyProfile initPolicyProfile(InsuranceModel.Customer customer)
{
    PolicyKind policyKind = PolicyKind.GetTypeOf(policy);
    InsuranceModel.HealthPolicy prototypeHealth = InsuranceModel.HealthPolicy.Create();
    InsuranceModel.VehiclePolicy prototypeVehicle = InsuranceModel.VehiclePolicy.Create();
    InsuranceModel.TravelPolicy prototypeTravel = InsuranceModel.TravelPolicy.Create();
    PolicyKind healthKind = PolicyKind.GetTypeOf(prototypeHealth);
    PolicyKind vehicleKind = PolicyKind.GetTypeOf(prototypeVehicle);
    PolicyKind travelKind = PolicyKind.GetTypeOf(prototypeTravel);
    InsuranceModel.PolicyProfile profile = InsuranceModel.PolicyProfile.Create();
    profile.customerRef = customer;
    switch policyKind.Name
    {
        case healthKind.Name:
            profile.healthPolicy = policy as InsuranceModel.HealthPolicy;
            profile.riskTier = 1;
            profile.isCovered = true;
        case vehicleKind.Name:
            profile.vehiclePolicy = policy as InsuranceModel.VehiclePolicy;
            profile.riskTier = 2;
            profile.isCovered = true;
        case travelKind.Name:
            profile.travelPolicy = policy as InsuranceModel.TravelPolicy;
            profile.riskTier = 3;
            profile.isCovered = false;
        default:
            profile.isCovered = false;
            profile.riskTier = 99;
    }
    return profile;
}

