function bool HasBookingConflict(int roomId, DateTime start, DateTime end)
{
   Collection[Domain.Booking] existing = Domain.Booking.Find(b => b.RoomId == roomId && b.IsActive);
    bool overlaps = existing.Any(b => (start < b.EndDate) && (end > b.StartDate));
    bool isMaintenancePeriod = this.MaintenanceSchedules.Any(s => s.RoomId == roomId && s.IsLocked);
    return overlaps || isMaintenancePeriod;
}

