static function HealthModel.PatientRecordBundle initPatientRecordBundle(HealthModel.Patient patient)
{
    RecordType medicalKind = RecordType.GetTypeOf(record);
    HealthModel.SurgeryRecord prototypeSurgery = HealthModel.SurgeryRecord.Create();
    HealthModel.DiagnosisRecord prototypeDiagnosis = HealthModel.DiagnosisRecord.Create();
    HealthModel.PrescriptionRecord prototypePrescription = HealthModel.PrescriptionRecord.Create();
    HealthModel.LabRecord prototypeLab = HealthModel.LabRecord.Create();
    RecordType surgeryKind = RecordType.GetTypeOf(prototypeSurgery);
    RecordType diagnosisKind = RecordType.GetTypeOf(prototypeDiagnosis);
    RecordType prescriptionKind = RecordType.GetTypeOf(prototypePrescription);
    RecordType labKind = RecordType.GetTypeOf(prototypeLab);
    HealthModel.PatientRecordBundle bundle = HealthModel.PatientRecordBundle.Create();
    bundle.primaryPatient = patient;
    bundle.isArchived = false;
    if(medicalKind.Name == surgeryKind.Name) {
        bundle.surgeryRecord = record as HealthModel.SurgeryRecord; }
    elseif(medicalKind.Name == diagnosisKind.Name) {
        bundle.diagnosisRecord = record as HealthModel.DiagnosisRecord; }
    elseif(medicalKind.Name == prescriptionKind.Name) {
        bundle.prescriptionRecord = record as HealthModel.PrescriptionRecord; }
    elseif(medicalKind.Name == labKind.Name) {
        bundle.labRecord = record as HealthModel.LabRecord;
    }
    return bundle;
}

