function Collection[Domain.Track] GetHighQualityTracks(Domain.Playlist pl, int minBitrate) {
    Collection[Domain.Track] results;
    int level = 1;
    foreach track in pl.Tracks {
        if (minBitrate > 128) {
            results = this.AddTrackToAudit(track, level, results);
        }
    }
    if (pl.SubPlaylists.Length > 0) {
        results = this.GetTracksInner(pl, results, minBitrate);
    }
    return results;
}
function Collection[Domain.Track] GetTracksInner(Domain.Playlist p, Collection[Domain.Track] nodes, int minBitrate) {
    int level = 2;
    foreach sub in p.SubPlaylists {
        if (sub.Tracks.Length > 0) {
             nodes = this.GetTracksInner(sub, nodes, minBitrate);
        }
        else if (minBitrate > 128) {
            nodes = this.AddTrackToAudit(sub, level, nodes);
        }
    }
    return nodes;
}

